651	/// Extract model tier from verbatim model ID string.
652	/// Returns "opus", "sonnet", "haiku", or "unknown".
653	fn zjjrm_extract_tier(model: &str) -> &'static str {
654	    let lower = model.to_ascii_lowercase();
655	    if lower.contains("opus") {
656	        "opus"
657	    } else if lower.contains("sonnet") {
658	        "sonnet"
659	    } else if lower.contains("haiku") {
660	        "haiku"
661	    } else {
662	        "unknown"
663	    }
664	}
