666	/// Gate check: require opus-tier model. Returns Err with diagnostic on failure.
667	fn zjjrm_check_model_gate(model: &str) -> Result<(), String> {
668	    let tier = zjjrm_extract_tier(model);
669	    if tier == "opus" {
670	        return Ok(());
